#include <bits/stdc++.h>
using namespace std;
const int N=200005,mod=998244353;
long long n,dp[N],sum[N];
string s;
int main()
{
    cin>>n>>s;
    s=" "+s;
    dp[1]=s[1]-'0';
    sum[1]=dp[1]+1;
    for(int i=2;i<=n;i++)
    {
        dp[i]=(10*dp[i-1]+(s[i]-'0')*sum[i-1])%mod;
        sum[i]=(sum[i-1]+dp[i])%mod;
    }
    cout<<dp[n];
    return 0;
}
